// Parse Lightspeed portfolio companies from Consider page HTML
const items = $input.all();
const html = String(items[0]?.json?.data || items[0]?.json || '');
const results = [];
const seen = new Set();
const today = new Date().toISOString().split('T')[0];
const vcName = 'Lightspeed';

// Extract company link and name: href="/jobs/slug" ... class="job-boards-company-name">Name<
const pattern = /href="\/jobs\/([^"]+)"[\s\S]*?class="[^"]*job-boards-company-name[^"]*"[^>]*>([^<]+)</gi;
let match;
while ((match = pattern.exec(html)) !== null) {
  const slug = match[1].trim();
  const name = match[2].trim();
  if (!name || name.length < 2) continue;

  const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seen.has(key)) continue;
  seen.add(key);

  const url = 'https://jobs.lsvp.com/jobs/' + slug;

  results.push({
    json: {
      'Company Name': name,
      'VC Firm': vcName,
      'Company Description': name + ' - Lightspeed portfolio company',
      'Company URL': url,
      'Stage': '',
      'Employee Count': '',
      'Status': 'New',
      'First Seen Date': today,
      'Source': 'VC Portfolio'
    }
  });
}

if (results.length === 0) {
  const hasCompanyItems = html.includes('job-boards-company-item');
  const hasCompanyNames = html.includes('job-boards-company-name');
  return [{ json: { _empty: true, _message: 'No companies found', vcName: vcName, htmlLength: html.length, hasCompanyItems: hasCompanyItems, hasCompanyNames: hasCompanyNames } }];
}

return results;
